import React from 'react';
import { Link, NavLink } from 'react-router-dom';
import { FiBell, FiUser } from 'react-icons/fi';
import { useAuth } from '../../context/AuthContext';

const Navbar = () => {
  const { user, isAdmin } = useAuth();
  const dashboardPath = isAdmin?.() ? '/admin/dashboard' : '/dashboard';

  return (
    <header className="topbar">
      <div className="topbar-left">
        <Link to={dashboardPath} className="topbar-title">
          Campus Booking System
        </Link>

        <nav className="topbar-tabs" aria-label="Primary">
          <NavLink
            to={dashboardPath}
            className={({ isActive }) => `topbar-tab ${isActive ? 'active' : ''}`}
            end
          >
            Overview
          </NavLink>
          <NavLink
            to="/bookings"
            className={({ isActive }) => `topbar-tab ${isActive ? 'active' : ''}`}
          >
            Schedule
          </NavLink>
          <NavLink
            to="/rooms"
            className={({ isActive }) => `topbar-tab ${isActive ? 'active' : ''}`}
          >
            Reports
          </NavLink>
        </nav>
      </div>

      <div className="topbar-right">
        <button type="button" className="icon-btn topbar-icon-btn" aria-label="Notifications">
          <FiBell />
          <span className="notification-dot" />
        </button>

        <div className="nav-user topbar-user">
          <FiUser />
          <span>{user?.name || 'Campus User'}</span>
        </div>
      </div>
    </header>
  );
};

export default Navbar;
